from dataclasses import dataclass
from typing import List
import math

@dataclass
class Trade:
    entry_price: float
    exit_price: float
    quantity: float
    is_long: bool

    @property
    def pnl(self) -> float:
        if self.is_long:
            return (self.exit_price - self.entry_price) * self.quantity
        else:
            return (self.entry_price - self.exit_price) * self.quantity

class PerformanceCalculator:
    def __init__(self, trades: List[Trade], initial_capital: float):
        self.trades = trades
        self.initial_capital = initial_capital

    def total_pnl(self) -> float:
        return sum(t.pnl for t in self.trades)

    def win_rate(self) -> float:
        if not self.trades:
            return 0.0
        winners = sum(1 for t in self.trades if t.pnl > 0)
        return (winners / len(self.trades)) * 100

    def profit_factor(self) -> float:
        gross_profit = sum(t.pnl for t in self.trades if t.pnl > 0)
        gross_loss = abs(sum(t.pnl for t in self.trades if t.pnl < 0))
        if gross_loss == 0:
            return float('inf') if gross_profit > 0 else 0.0
        return gross_profit / gross_loss

    def average_win(self) -> float:
        winners = [t.pnl for t in self.trades if t.pnl > 0]
        return sum(winners) / len(winners) if winners else 0.0

    def average_loss(self) -> float:
        losers = [t.pnl for t in self.trades if t.pnl < 0]
        return sum(losers) / len(losers) if losers else 0.0

    def expectancy(self) -> float:
        if not self.trades:
            return 0.0
        return self.total_pnl() / len(self.trades)

    def max_drawdown(self) -> float:
        if not self.trades:
            return 0.0

        equity = self.initial_capital
        peak = equity
        max_dd = 0.0

        for trade in self.trades:
            equity += trade.pnl
            if equity > peak:
                peak = equity
            dd = (peak - equity) / peak * 100
            max_dd = max(max_dd, dd)

        return max_dd

    def summary(self) -> dict:
        return {
            "total_trades": len(self.trades),
            "total_pnl": f"${self.total_pnl():,.2f}",
            "win_rate": f"{self.win_rate():.1f}%",
            "profit_factor": f"{self.profit_factor():.2f}",
            "avg_win": f"${self.average_win():,.2f}",
            "avg_loss": f"${self.average_loss():,.2f}",
            "expectancy": f"${self.expectancy():,.2f}",
            "max_drawdown": f"{self.max_drawdown():.2f}%"
        }

# Test
trades = [
    Trade(100, 110, 10, True),
    Trade(110, 105, 10, True),
    Trade(105, 115, 10, True),
    Trade(115, 108, 10, True),
    Trade(108, 120, 10, True),
    Trade(50, 45, 20, False),
    Trade(45, 48, 20, False),
]

calc = PerformanceCalculator(trades, initial_capital=10000)
for key, value in calc.summary().items():
    print(f"{key}: {value}")
